solutions.javascript:
// Solution
function mergeObjects<T>(obj1: T, obj2: T): T {
    let merged: T = {};
    for (let key in obj1) {
        if (!(key in merged)) {
            merged[key] = obj1[key];
        }
    }
    for (let key in obj2) {
        if (!(key in merged)) {
            merged[key] = obj2[key];
        }
    }
    return merged;
}
